package main

import (
	"context"
	"fmt"
	"math"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// Limits to reduce risk from untrusted user scripts.
const (
	maxScriptSize   = 64 * 1024
	maxContextItems = 256
	luaCallTimeout  = 100 * time.Millisecond
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
//
// Security hardening:
// - Enforces script size and context size limits.
// - Runs script execution with a context timeout.
// - Validates numeric inputs/outputs to reject NaN/Inf.
// - Exposes only the standard libraries available in this gopher-lua version.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	if len(script) == 0 {
		return 0, fmt.Errorf("script is empty")
	}
	if len(script) > maxScriptSize {
		return 0, fmt.Errorf("script exceeds maximum allowed size")
	}
	if len(ctx) > maxContextItems {
		return 0, fmt.Errorf("context exceeds maximum allowed size")
	}

	execCtx, cancel := context.WithTimeout(context.Background(), luaCallTimeout)
	defer cancel()

	L := lua.NewState(lua.Options{})
	defer L.Close()
	L.SetContext(execCtx)

	if err := L.DoString(script); err != nil {
		if execCtx.Err() == context.DeadlineExceeded {
			return 0, fmt.Errorf("failed to execute Lua script: script execution timed out")
		}
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	ctxTable := L.NewTable()
	for k, v := range ctx {
		if !isFinite(v) {
			return 0, fmt.Errorf("context value for key %q is not a finite number", k)
		}
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		if execCtx.Err() == context.DeadlineExceeded {
			return 0, fmt.Errorf("failed to call calculate_final_price: script execution timed out")
		}
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	result := L.Get(-1)
	L.Pop(1)

	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	price := float64(result.(lua.LNumber))
	if !isFinite(price) {
		return 0, fmt.Errorf("calculate_final_price returned a non-finite number")
	}

	return price, nil
}

func isFinite(v float64) bool {
	return !math.IsNaN(v) && !math.IsInf(v, 0)
}

func main() {
	script := `
function calculate_final_price(ctx)
	if ctx.user_tier >= 2 then
		return ctx.base_price * 0.9
	else
		return ctx.base_price
	end
end
`

	ctx := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2,
	}

	price, err := ExecutePricingScript(script, ctx)
	if err != nil {
		fmt.Println("error:", err)
		return
	}

	fmt.Println("final price:", price)
}

